import { getMockApiUrls } from "./get-mock-api-urls";
import { expect, test } from "./test-fixture";

const urls = getMockApiUrls();

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

test("creates an organization tenant and returns to the homepage", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [] });

  await page.goto("/organizations/new");

  await page.locator("#organization-name").fill("Acme co");

  await page
    .getByRole("button")
    .filter({ has: page.getByText("Organization", { exact: true }) })
    .click();

  const createdTenant = {
    id: 42,
    tenant_type: "org" as const,
    name: "Hope Foundation",
    org_id: "org-42",
    vendor_id: null,
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  // Swap the GET /tenants response and register the POST + campaigns mocks
  // before submitting. Re-using the same RegExp keys overwrites RMP's Map
  // entry (see `MockClient.addMock` which keys by the reqSchema reference).
  // We intentionally avoid `mockServerRequest.reset()` here because clearing
  // all handlers mid-test races with any in-flight server requests and is the
  // known flake source called out in `tests/campaigns.spec.ts`.
  await mockServerRequest.GET(urls.tenants, { body: [createdTenant] });
  await mockServerRequest.POST(urls.tenants, { body: createdTenant });
  await mockServerRequest.GET(urls.campaignsIndex(42), { body: [] });

  await page.getByRole("button", { name: "Create organization" }).click();

  await expect(page).toHaveURL(/\/$/);
});

test("creates a vendor tenant and returns to the homepage", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [] });

  await page.goto("/organizations/new");

  await page.locator("#organization-name").fill("Acme Vendor Co");
  await page
    .getByRole("button")
    .filter({ has: page.getByText("Vendor", { exact: true }) })
    .click();

  const createdTenant = {
    id: 43,
    tenant_type: "vendor" as const,
    name: "Acme Vendor Co",
    org_id: null,
    vendor_id: "ven-43",
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  // See note above on avoiding mid-test `reset()`. Overwrite the GET /tenants
  // response and register the POST + campaigns mocks in place.
  await mockServerRequest.GET(urls.tenants, { body: [createdTenant] });
  await mockServerRequest.POST(urls.tenants, { body: createdTenant });
  await mockServerRequest.GET(urls.campaignsIndexVendor(43, 43), { body: [] });

  await page.getByRole("button", { name: "Create organization" }).click();

  await expect(page).toHaveURL(/\/$/);
});

